+            && key.key_type == KeyType::Runes && key.runes.contains(&'q')
+        {
+            return Some(quit());
+        }
+        None
+    }
+
+    fn view(&self) -> String {
+        let title = lipgloss::Style::new().bold().render("Title");
+        let body = lipgloss::Style::new().italic().render("Body text");
+        format!("{title}\n{body}")
+    }
+}
